class Solution:
    def sumEvenAfterQueries(self, nums, queries):
        arr = list(nums)
        even = sum(x for x in arr if x % 2 == 0)
        out = []
        for val, idx in queries:
            if arr[idx] % 2 == 0:
                even -= arr[idx]
            arr[idx] += val
            if arr[idx] % 2 == 0:
                even += arr[idx]
            out.append(even)
        return out

