var sumEvenAfterQueries = function(nums, queries) {
    const arr = nums.slice();
    let even = 0;
    for (const x of arr) if (x % 2 === 0) even += x;
    const out = [];
    for (const [val, idx] of queries) {
        if (arr[idx] % 2 === 0) even -= arr[idx];
        arr[idx] += val;
        if (arr[idx] % 2 === 0) even += arr[idx];
        out.push(even);
    }
    return out;
};
